                    // C: dojump(ci, i, 0) → pc += GETARG_sJ(i) + 0; updatetrap(ci);
                    OpCode::Jmp => {
                        pc = (pc as i64 + i.arg_s_j() as i64) as u32;
                        trap = state.ci_trap(ci);
                    }
