                    // C: op_arithI(L, l_addi, luai_numadd)
                    OpCode::AddI => {
                        let ra = base + i.arg_a();
                        let v1 = state.get_at(base + i.arg_b()).clone();
                        let imm = i.arg_s_c() as i64;
