                    }
                    // C: op_arithK(L, luaV_idiv, luai_numidiv)
                    OpCode::IDivK => {
                        let ra = base + i.arg_a();
                        let v1 = state.get_at(base + i.arg_b()).clone();
                        let v2 = state.proto_const(&cl, i.arg_c() as usize).clone();
                        state.set_ci_savedpc(ci, pc);
                        state.set_top(state.ci_top(ci));
