                    // ── OP_NEWTABLE ───────────────────────────────────────────
                    // C: b = log2(hash size)+1; c = array size
                    //    if (TESTARG_k(i)) c += GETARG_Ax(*pc) * (MAXARG_C + 1); pc++;
                    OpCode::NewTable => {
                        let ra = base + i.arg_a();
                        let mut b = i.arg_b();
                        let mut c = i.arg_c();
                        if b > 0 {
                            b = 1 << (b - 1); // C: b = 1 << (b - 1)
                        }
